931	  /**
932	   * Production milestone timeline derived from the item's real date fields.
933	   * Each milestone is `done` (date in the past), `current` (next upcoming /
934	   * first without a past date) or `todo`.
935	   */
936	  get timelineItems(): { label: string; date: any; state: 'done' | 'current' | 'todo' }[] {
937	    const ci = this.itemData?.[0];
938	    if (!ci) return [];
939	    const points = [
940	      { label: 'Created', date: ci.created_time_date },
941	      { label: 'Test Report', date: ci.udf_date02 },
942	      { label: 'Photography', date: ci.udf_date03 },
943	      { label: 'Due', date: ci.due_date },
944	      { label: 'On Shelf', date: ci.udf_date01 },
945	    ];
946	    const now = Date.now();
947	    let currentAssigned = false;
948	    return points.map((p) => {
949	      const t = p.date ? new Date(p.date).getTime() : NaN;
950	      let state: 'done' | 'current' | 'todo';
951	      if (!isNaN(t) && t < now) {
952	        state = 'done';
953	      } else if (!currentAssigned) {
954	        state = 'current';
955	        currentAssigned = true;
956	      } else {
957	        state = 'todo';
958	      }
959	      return { label: p.label, date: p.date, state };
960	    });
961	  }
