104	  getImageAttachments = async () => {
105	    this.GalleryItems = [];
106	    this.imageSliderObject = [];
107	    this.detailImages = [];
108	    this.detailThumbs = [];
109	
110	    this.itemService.getItemAttachements(this.itemDetailId).toPromise().then(async(itemDetailsData: any) => {
111	      this.itemAttachments = itemDetailsData;
112	
113	      if (itemDetailsData.length > 0 && this.primaryImage) {
114	        const primary = this.itemAttachments.find(item => item.uuid === this.primaryImage);
115	        if (primary) {
116	          const isDesignOnly = !!primary.dsn_ref_num;
117	          this.designOnlyStatusChange.emit(isDesignOnly);
118	        }
119	      } else if (itemDetailsData.length > 0) {
120	        const firstImage = itemDetailsData.find(item => item.attachment_display_name === 'Image');
121	        if (firstImage) {
122	          const isDesignOnly = !!firstImage.dsn_ref_num;
123	          this.designOnlyStatusChange.emit(isDesignOnly);
124	        }
125	      } else {
126	        this.designOnlyStatusChange.emit(false);
127	      }
128	
129	      itemDetailsData = itemDetailsData.filter(item => item.item_attachment_fileName.toLowerCase() !== 'no_image.jpg')
130	
131	      // Separate images and thumbnails into detailImages and detailThumbs arrays
132	      itemDetailsData.forEach(element => {
133	        if(element.primary_image) this.primaryImage = element.uuid
134	       // if (element.uuid) {
135	          if (element.attachment_display_name === 'Image') {
136	            this.detailImages.push(element);
137	          } else if (element.attachment_display_name === 'Thumb') {
138	            this.detailThumbs.push(element);
139	          }
140	       // }
141	      });
142	
143	      // Combine images and thumbnails using UUID for synchronization
144	      this.detailImages.forEach(image => {
145	        const matchingThumb = this.detailThumbs.find(thumb => thumb.uuid === image.uuid);
146	        if (matchingThumb) {
147	          this.GalleryItems.push(new ImageItem({ src: image.attachment_link }));
148	          this.imageSliderObject.push({
149	            thumbImage: matchingThumb.attachment_link,
150	            uuid: matchingThumb.uuid,
151	          });
152	        }
153	      });
154	
155	      // By default set one primary image if available else show no image
156	      if(itemDetailsData.length > 0 && !this.primaryImage){
157	        const defaultItem = itemDetailsData.find((item => item.uuid !== null)) || itemDetailsData[0];
158	        if(defaultItem.uuid) this.changePrimary(defaultItem.uuid)
159	          else{
160	                // If the image does not have uuid, add one
161	                const uuid = defaultItem.uuid || uuidv4()
162	                let fileName = defaultItem.item_attachment_fileName;
163	                fileName = (defaultItem.attachment_display_name.toLowerCase() === 'image') ? fileName.replace('images-','') : fileName.replace('thumbs-','')
164	                await this.updateUuid(uuid, defaultItem.item_num_id_fk, fileName, true);
165	                this.getImageAttachments();
166	        }
167	      } else if(itemDetailsData.length === 0) {
168	        this.GalleryItems.push(new ImageItem({ src: this.noImage }));
169	        this.imageSliderObject.push({
170	          thumbImage: this.noImage
171	        });
172	      }
173	
174	      // Make sure input is cleared to detect file upload change if you upload same files again
175	      const imageInput = document.getElementById('image') as HTMLInputElement;
176	      imageInput && (imageInput.value = '');
177	
178	          // Load the images into the gallery
179	      this.galleryRef.load([...this.GalleryItems]);
180	    })
181	  }
