/**
 * Refresh the Item Library cache/grid after a successful item edit so the
 * library grid is not stale (mirrors onStyleNumber). Clears the localStorage
 * 'itemLibrary' cache and reloads the grid from the service when available.
 */
private async refreshItemLibraryCache(): Promise<void> {
  localStorage.removeItem('itemLibrary');
  try {
    const itemLibraryService = window["ItemLibraryService"];
    if (!itemLibraryService?.getAllitems) {
      return;
    }
    const data: any = await firstValueFrom(itemLibraryService.getAllitems());
    window['params']?.api?.setRowData(data);
    data.push({ expirationTime: Date.now() });
    localStorage.setItem('itemLibrary', JSON.stringify(data));
  } catch (err) {
    console.error('[ItemDetailComponent] ItemLibraryService.getAllitems failed:', err);
  }
}
